sql:
SELECT COUNT(*) AS total_revisions
FROM size_revisions
WHERE size_id = 1;

SELECT MAX(revision_date)
FROM size_revisions
WHERE size_id = 1;

SELECT user_name 
FROM users 
ORDER BY user_name;

